window.__dh_data["af"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Dhammapada",
  "chaps": "Hoofstukke",
  "fontsize": "Lettergrootte",
  "chap1": "Pare",
  "1": "Denke lei, bepaal en vorm ervarings: as 'n mens uit troebel dink praat of doen volg verdriet jou soos 'n wiel die poot van 'n trekos.",
  "2": "Denke lei, bepaal en vorm ervarings: as 'n mens uit helder dink praat of doen volg geluk jou soos 'n skadu wat altyd by jou bly.",
  "3": "'Hy het my beledig, aangerand, oorrompel, beroof!' Wie 'n wrok teenoor so 'n mens koester se haat bedaar nie.",
  "4": "'Hy het my beledig, aangerand, oorrompel, beroof!' Wie nie 'n wrok teenoor so 'n mens koester nie se haat bedaar.",
  "5": "Want in hierdie wêreld bedaar haat nooit deur haat nie; haat bedaar deur nie-haat – dit is 'n tydlose wet.",
  "6": "Party mense besef nie dat ons almal hier tot 'n einde kom nie, maar wie dit besef se twiste kom tot 'n einde.",
  "7": "Soos die wind 'n swak boom, so oorwin Māra 'n mens wat op die uitkyk na plesier leef, sintuiglik onbeheers, onmatig in voedsel, ledig en lui.",
  "8": "So min as die wind 'n berg van klip, so min oorwin Māra 'n mens wat op die uitkyk na onplesier leef, sintuiglik beheers, matig in voedsel, getrou en vasberade.",
  "9": "'n Mens wat die geel kleed omhang al is hy nie sonder smet nie en van selfbeheer en waarheid ontdaan is die geel kleed nie werd nie.",
  "10": "Maar 'n mens wat van smette gereinig in deugde gevestig en met selfbeheer og waarheid beklee is, só een is die geel kleed werd.",
  "11": "Wie dink dat onwesenlik wesenlik is en wesenlik vir onwesenlik aansien, wei in verkeerde voornemens en bereik nie wat wesenlik is nie.",
  "12": "Wie wesenlik as wesenlik ken en onwesenlik as onwesenlik, wei in regte voornemens en bereik wat wesenlik is.",
  "13": "Soos reën in 'n sleg bedekte huis inlek so lek in 'n swak ontwikkelde gemoed begeerte in.",
  "14": "Soos reën nie in 'n goed bedekte huis inlek nie so lek in 'n sterk ontwikkelde gemoed begeerte nie in nie.",
  "15": "Hy is hier ongelukkig og hy is hierna ongelukkig; die boosdoener is in albei ongelukkig – is ongelukkig og kry swaar as hy die vlek van sy eie handeling sien.",
  "16": "Hy is hier gelukkig og hy is hierna gelukkig; die weldoener is in albei gelukkig – is gelukkig, intens gelukkig as hy die suiwerheid van sy eie handeling sien.",
  "17": "Hy ly hier og hy ly hierna; die boosdoener ly in albei – hy ly as hy besef: 'ek het boos gedoen' en hy ly nog meer as hy die bestemming van onheil bereik het.",
  "18": "Hy is hier bly og hy is hierna bly; die weldoener is in albei bly – hy is bly as hy besef: 'ek het goed gedoen' en hy is nog blyer as hy die bestemming van heil bereik het.",
  "19": "As iemand groot dele van die geskrifte opsê og voorsê maar nie 'n doener daarvan is nie, is hy 'n nalatige mens; soos 'n beeswagter wat ander se beeste tel deel hy nie in die swerwersbestaan nie.",
  "20": "As iemand min uit die geskrifte opsê maar volgens die waarheid leef: onsae van begeerte, weersin og verblinding, noulettend, met bevryde gees, aan niks hier of daar verkleef nie, deel hy in die swerwersbestaan.",
  "chap2": "Agsaamheid",
  "21": "Agsaamheid is die pad van nie-dood, onagsaamheid die pad van dood; agsames sterf nie, onagsames is soos dood.",
  "22": "Wie hierdie onderskeid ken, vind, in agsaamheid geskoold, vreugde in die agsaamheid en geluk in die edeles se domein.",
  "23": "Wie bestendig mediteer, deurlopend volhardend inspannend, ervaar nibbāna: die allervryste losmaak uit gebondenheid.",
  "24": "Ontsag vir een wat agsaam is, neem toe – een wat vasberade en aandagtig in helder og oorwoë daad beheers is en die waarheid leef.",
  "25": "Met vasberadenheid og agsaamheid beheersdheid og matigheid sal 'n wyse mens 'n eiland bou wat geen vloed sal kan oorstroom nie.",
  "26": "Onvolwasse dwase gee hulle oor aan agloosheid maar 'n wyse mens koester agsaamheid as die grootste rykdom.",
  "27": "Gee julle nie oor aan agloosheid en die ervaring van plesiergenot; wie agsaam mediteer verkry oorvloedige geluk.",
  "28": "Wanneer 'n wyse mens agloosheid met agsaamheid verdryf bestyg hy leedloos die burg van insig en neem as sterk-wyse die lydende mensdom waar soos een wat op 'n berg staan, die onwetende mensdom daaronder.",
  "29": "Agsaam onder onagsames onder slapendes helder wakker − soos 'n gewillige perd 'n steeks perd agterlaat gaan 'n waarlik wyse mens vooruit.",
  "30": "Deur agsaamheid het Maghavā voorrang onder die gode verkry; hulle prys agsaamheid, onagsaamheid word altyd afgekeur.",
  "31": "Die monnik wat in agsaamheid vreugde vind og in onagsaamheid gevaar sien, beweeg soos vuur, verbrand elke belemmering, gering og grof.",
  "32": "Die monnik wat in agsaamheid vreugde vind og in onagsaamheid gevaar sien, sal nie val nie, is naby nibbāna.",
  "chap3": "Gemoed",
  "33": "Sy onseker trillende gemoed moeilik om te hanteer en beheer buig 'n wyse mens reguit soos 'n pylmaker 'n steel.",
  "34": "Soos 'n vis uit sy watertuiste geruk en op droë grond gegooi, sidder die gemoed; ontsnap uit Māra se domein.",
  "35": "Dit is moeilik om die gemoed te beheer want dit fladder vinnig na hartelus rond; om dit te tem, is goed – 'n getemde gemoed gee geluk.",
  "36": "Dit is moeilik om die gemoed waar te neem want dit fladder vlugtig na hartelus rond; laat die wyse mens dit bewaak – 'n bewaakte gemoed gee geluk.",
  "37": "Sonder lyf loop die gemoed ver, dwaal alleen, skuil in 'n grot − van die bande van die Bose sal julle loskom as julle die gemoed in toom kan hou.",
  "38": "'n Mens met onstandvastige gemoed wat die goeie waarheid nie deeglik ken nie en net weifelend vertrou se wysheid bly onvolmaak.",
  "39": "'n Ontwaakte mens wie se gemoed nie deurweek is en nie getreiter word nie og goed en boos agtergelaat het is vreesloos.",
  "40": "Weet dat die liggaam soos 'n kleipot is maar laat die gemoed soos 'n vesting staan; beveg die Bose met die wapen van wysheid en beskerm jou buit – maar bly onverknog.",
  "41": "Ja, hierdie lyf sal gou bewusloos verlate soos 'n verrottende stomp op die grond gaan lê.",
  "42": "Jou eie verkeerd-gerigte gemoed doen jouself veel meer kwaad as die kwaad wat vyand aan vyand of hater aan hater sou kon doen.",
  "43": "Jou eie wel-gerigte gemoed doen jouself veel meer goed as die goed wat moeder of vader of ander familie sou kon doen.",
  "chap4": "Blomme",
  "44": "Wie sal hierdie aarde bemeester en die domeine van Yama en die gode? Wie sal die wel-onderwese waarheidsweg kies soos 'n kenner 'n blom?",
  "45": "'n Leerling sal hierdie aarde bemeester en die domeine van Yama en die gode. 'n Leerling sal die wel-onderwese waarheidsweg kies soos 'n kenner 'n blom.",
  "46": "Weet dat hierdie liggaam soos skuim is, besef dat waan sy wese is; breek Māra se blompuntpyle en jy sal buite sig van die Doodsvors beweeg.",
  "47": "Mens, as jy met begerende gees blomme pluk sleur die dood jou mee soos 'n groot vloed 'n slapende dorp.",
  "48": "Mens, as jy met begerende gees wat nooit genoeg geniet nie blomme pluk oorweldig die Beëindiger jou.",
  "49": "Soos 'n by nektar opneem en van die blom af wegvlieg sonder om kleur of geur te skaad so beweeg 'n wyse mens in die dorp.",
  "50": "Laat 'n mens let nie op ander se oortredings en hulle doen en nie-doen nie maar alleenlik op jou eie.",
  "51": "Soos 'n mooi blom vol kleur maar sonder geur is 'n mooi woord vrugteloos as doen dit nie volg nie.",
  "52": "Soos 'n mooi blom vol kleur en vol geur is 'n mooi woord vrugbaar as doen dit volg.",
  "53": "Soos uit 'n massa blomme 'n mens baie kranse kan vleg sal 'n gebore sterfling menige mooi daad kan vleg.",
  "54": "Die geur van blomme versprei nie windop nie selfs nie die geur van sandel of tagara of jasmyn nie; maar die geur van deugsames versprei windop − 'n goeie mens geur in alle rigtings.",
  "55": "Soeter as die geur van sandelhout en tagara waterlelie en jasmyn is die geur van deug.",
  "56": "Gering is die geur van tagara en sandelhout maar groots is die geur van deugsames − dit sweef op tot by die gode.",
  "57": "Māra vind nie die weg van hulle wat waarlik deugsaam is, in agsaamheid woon en deur die hoogste wete vry is nie.",
  "58": "Op 'n afvalhoop langs die grootpad verwerp groei 'n lotus welriekend geesverblydend.",
  "59": "Te midde van vervalle wesens − 'n verblinde mensemassa − skyn in helder wysheid 'n volgeling van die Volverligte.",
  "chap5": "Dwase",
  "60": "Lank is die nag vir 'n slaaplose lank is die skof vir 'n moeë lank is die kringloop van bestaan vir dwase wat die goeie waarheid nie ken nie.",
  "61": "As jy op jou reis niemand ontmoet wat jou meerdere of gelyke is nie, reis dan vasberade alleen wen 'n dwaas is geen metgesel nie.",
  "62": "'Ek het seuns, ek het rykdom' dink die dwaas angstig; hy het nie eens homself nie, waar kom hy aan seuns en rykdom?",
  "63": "'n Dwaas wat sy dwaasheid besef, is dáárom wys maar 'n dwaas wat hom verbeel hy is wys, wordt tereg 'n dwaas genoem.",
  "64": "Al verkeer 'n dwaas lewenslank in die geselskap van 'n wyse mens verstaan hy die waarheid net so min as 'n lepel die smaak van sop.",
  "65": "Al verkeer 'n oordeelkundige net 'n oomblik lank in die geselskap van 'n wyse mens verstaan hy die waarheid net so gou as 'n tong die smaak van sop.",
  "66": "Dwase dool dom rond en is hul eie vyand terwyl hulle verkeerde dade doen wat wrange vrugte dra.",
  "67": "'n Daad wat 'n mens berou en waarvan jy met trane op jou lippe die vrugte pluk, was nie 'n goeie daad nie.",
  "68": "'n Daad wat 'n mens nie berou nie en waarvan jy gelukkig en tevrede die vrugte pluk, was 'n goeie daad.",
  "69": "Voor 'n slegte daad vrugte dra, dink die dwaas dis heuningsoet, maar as die vrugte ryp is, stort hy in ellende neer.",
  "70": "Al eet 'n dwaas maand na maand sy kos met die punt van 'n kusa-spriet is hy nie 'n sestiende werd van hulle wat die waarheid begryp nie.",
  "71": "Gedane kwaad is soos melk wat nie dadelik versuur nie; dit volg en brand die dwaas soos kole onder as bedek.",
  "72": "Slegs tot sy nadeel bekom 'n dwaas kennis; dit vernietig sy geluk en breek sy kop.",
  "73": "Die dwaas soek 'n onwesenlike reputasie, voorrang onder monnike, mag in kloosters en eerbetoon by families.",
  "74": "'Laat leke en monnike dink dat ék dit gedoen het, laat hulle in hul doen en late aan mý onderdanig wees'; dit is die dwaas se strewe en sy ambisie en arrogansie groei.",
  "75": "'n Middel tot wins is een ding, die pad na nibbāna 'n ander; laat die monnik, leerling van die Boeddha, dit deur ervaring weet, in roem nie vreugde vind nie maar afgeskeidenheid koester.",
  "chap6": "Die Wyse",
  "76": "Gaan met 'n wyse mens om wat foute opmerk en verstandig teregwys soos met iemand wat jou na 'n verborge skat toe lei; om met so 'n mens om te gaan, hou geen nadeel in nie, net voordeel.",
  "77": "Laat hom raadgee en onderrig en jou van kwaad weerhou; by deugsames is hy geliefd, by ondeugsames ongeliefd.",
  "78": "Gaan nie om met vriende gemeen en laag nie; gaan om met vriende goed en hoogstaande.",
  "79": "Wie waarheid drink, leef rustig met helder gemoed; aan waarheid deur edeles onderrig, het 'n wyse immer vreugde.",
  "80": "Ingenieurs lei water, pylmakers buig stele, houtwerkers vorm hout, wyses bemeester hulleself.",
  "81": "Soos 'n vaste rots voor geen wind wyk nie so swig wyse mense nie voor blaam of loflied nie.",
  "82": "Soos 'n diep dam helder en kalm word wyse mense stil: hulle het die leringe gehoor.",
  "83": "Deugsames laat alle dinge kom og gaan, goeies babbel nie smagtend na plesier nie; wyses deur plesier en pyn geraak vlieg nie hoog of sak in dieptes weg nie.",
  "84": "'n Mens wat nie ter wille van homself of iemand anders nageslag of rykdom of koninkryk begeer en wens vir eie voordeel onregmatig verkry nie, is deugsaam, wys en waaragtig.",
  "85": "Min mensekinders kom anderkant uit, die meeste draf op die wal aan die duskant rond;",
  "86": "maar mense wat in die waarheid en die goeie lering daarvan leef, bereik die ander kant; oorsteek van die doodsdomein is swaar.",
  "87": "Laat die wyse mens die donker weg verlaat en steeds verder op die helder weg beweeg van huislikheid na afgeskeie huisloosheid, so moeilik te geniet.",
  "88": "Laat die wyse mens niks besit, sintuiglike genot oorskry, hom van gemoedsonsuiwerhede reinig, uitsien na genoeë dáár.",
  "89": "Menses van wie die gemoed goed ontwikkeld is in die faktore van verligting en wat vreugde vind in nie-vashou aan prysgee van vasgryp nie, het van die gif ontslae geraak en is helder-ligtendes: bereik in die wêreld nibbāna volledig.",
  "chap7": "Die Arahant",
  "90": "Iemand wat die reis voltooi het, leedloos volkome vry is en alle bande verbreek het word nie deur koors gekwel nie.",
  "91": "Aandagtiges vertrek, vind vreugde nie in 'n woning, verlaat skuiling na skuiling soos swane 'n dam.",
  "92": "Mense wat nie opgaar nie en wys is wat voedsel betref, wie se element leegheid is en vryheid sonder kenmerk se weg is moeilik om te volg soos dié van voëls in die luig.",
  "93": "'n Mens wat van smette skoon is en aan voedsel nie verslaaf nie, wie se element leegheid is en vryheid sonder kenmerk, se pad is moeilik om te volg soos dié van voëls in die lug.",
  "94": "Selfs die gode beny 'n smetlose mens, een met ydelheid uitgeskakel en sintuie gekalmeer soos getemde perde.",
  "95": "Iemand onskokbaar soos die aarde, stewig soos 'n pilaar van Indra helder soos 'n poel sonder slyk dool nie rond in kringlope van bestaan nie.",
  "96": "Stil die dink, stil die taal en stil die daad van 'n mens wat waarlik weet en waarlik vry bedaard is.",
  "97": "'n Mens wat nie glo nie, maar die ongemaakte verstaan, elke band verbreek, elke moontlikheid afgesny en elke begeerte uitgewerp het, is waarlik die hoogste mens.",
  "98": "Lieflik is die plek waar arahante woon - hetsy dorp of woud, vlakte of berg.",
  "99": "Wonderlik is wildernisse: waar ander behae nie vind nie, sal hartstogloses gelukkig wees, hulle wat plesier nie soek nie.",
  "chap8": "Duisende",
  "100": "Beter as 'n duisend nuttelose woorde saamgestring, is één nuttige woord hoor en rustig word.",
  "101": "Beter as 'n duisend nuttelose verse saamgestring, is één nuttige versreël hoor en rustig word.",
  "102": "Beter as 'n honderd saamgestringde nuttelose verse opsê, is één waarheidswoord hoor en rustig word.",
  "103": "In 'n veldslag kan één man 'n duisend maal duisend ander oorwin; 'n ander oorwin één: homself − en is die grootste oorwinnaar.",
  "104": "Beter is dit om jouself te oorwin as om ander te oorwin.",
  "105": "Selfs nie god of halfgod of Māra of Brahmā omskep oorwinning in nederlaag in 'n wese wat homself getem het en immer geïntegreerd leef nie.",
  "106": "Beter as om 'n honderd jaar lank maand na maand duisendmaal offerandes uit te voer, is dit om vir 'n enkele oomblik lank aan 'n enkele persoon van ontwikkelde gees eer te betoon.",
  "107": "Beter as om 'n honderd jaar lank die heilige vuur in die woud te bedien, is dit om vir 'n enkele oomblik lank aan 'n enkele persoon van ontwikkelde gees eer te betoon.",
  "108": "Al die gawes en offers in die wêreld wat 'n verdienste-soeker in 'n jaar sou kon bring, hou nie 'n kwart soveel voordeel in as eerbetoon aan hulle wat reguit loop nie.",
  "109": "In 'n mens wat uit inbors agting betoon en ontwikkeldes immer eer, ontwikkel vier kwaliteite: gesondheid, skoonheid, geluk en krag.",
  "110": "Dit is beter om 'n dag lank deugsaam en mediterend te leef as 'n eeu lank deugloos og koersloos.",
  "111": "Dit is beter om 'n dag lank wys en mediterend te leef as 'n eeu lank onwys og koersloos.",
  "112": "Dit is beter om 'n dag lank aktief met krag te leef as 'n eeu lank lui en swak.",
  "113": "Dit is beter om 'n dag lank te leef en ontstaan-vergaan in te sien as om 'n eeu lank te leef sonder om ontstaan-vergaan in te sien.",
  "114": "Dit is beter om 'n dag lank te leef en die weg na nie-dood in te sien as om 'n eeu lank te leef sonder om die weg na nie-dood in te sien.",
  "115": "Dit is beter om 'n dag lank te leef en die hoogste waarheid in te sien as om 'n eeu lank te leef sonder om die hoogste waarheid in te sien.",
  "chap9": "Boosheid",
  "116": "Maak gou om goed te doen en weerhou jou gemoed van boosheid; die gees van een wat traag goed doen geniet boosheid.",
  "117": "As iemand sleg sou doen, laat hom dit nie keer op keer weer doen nie, laat hom nie daarna begeer nie; leed is vermenigvuldiging van slegdoen.",
  "118": "As iemand reg sou doen, laat hom dit keer op keer weer doen, laat hom daarna verlang; geluk is vermenigvuldiging van regdoen.",
  "119": "Selfs 'n boosdoener ervaar goedheid solank die bose nie ryp geword het nie; maar wanneer die bose ryp geword het, ervaar 'n boosdoener die bose.",
  "120": "Selfs 'n goeddoener ervaar boosheid solank die goeie nie ryp geword het nie; maar wanneer die goeie ryp geword het, ervaar 'n goeddoener die goeie.",
  "121": "Dink nie gering van boosheid: 'dit kom tog nie na my toe terug nie' − 'n kruik word druppel vir druppel vol; van boosheid bietjie-bietjie doen, vul 'n dwaas homself met boosheid.",
  "122": "Dink nie gering van goedheid: 'dit kom tog nie na my toe terug nie' − 'n kruik word druppel vir druppel vol; van goedheid bietjie-bietjie doen, vul 'n wyse homself met goedheid.",
  "123": "Laat 'n mens bose dade vermy soos 'n handelaar met groot rykdom maar 'n klein karavaan 'n gevaarlike roete vermy og 'n mens wat sy lewe liefhet gif vermy.",
  "124": "As daar geen wond aan 'n hand is nie, kan mens gif in daardie hand dra; gif tas 'n hand sonder wond nie aan nie en daar is geen kwaad vir wie geen kwaad doen nie.",
  "125": "As jy 'n mens sonder kwaad kwaad aandoen – 'n mens vlekloos skoon – waai jou boosheid teen jouself terug soos stof teen die wind gegooi.",
  "126": "Sommige word in 'n moeder gebore, boosdoeners in 'n hel, wie goed leef, gaan hemel toe, onbesoedeldes bereik volkome bevryding.",
  "127": "Nêrens op aarde of in die luig of die diepte van die see of 'n grot in 'n berg is daar 'n skuilplek waar jy van 'n slegte daad kan loskom nie.",
  "128": "Nêrens op aarde of in die luig of die diepte van die see of 'n grot in 'n berg is daar 'n skuilplek waar die dood jou nie sal oorweldig nie.",
  "chap10": "Die Knuppel",
  "129": "Almal is bang vir 'n knuppel, almal beef voor die dood; plaas jouself in ander se plek: moenie doodmaak of laat doodmaak nie.",
  "130": "Almal is bang vir 'n knuppel, almal is lief vir die lewe; plaas jouself in ander se plek: moenie doodmaak of laat doodmaak nie.",
  "131": "Wie sy eie geluk nastreef en met 'n knuppel leed doen aan ander wesens wat ook geluk begeer, vind nie geluk as hy heengaan nie.",
  "132": "Wie sy eie geluk nastreef en nie met 'n knuppel leed doen aan ander wesens wat ook geluk begeer nie, vind geluk as hy heengaan.",
  "133": "Praat met niemand ru nie; met wie jy so praat, sal so terugpraat. Harde woorde is lyding, wedergeweld sal jou tref.",
  "134": "As jy stil is soos 'n gekraakte ghong het jy nibbāna bereik: daar is geen woede in jou nie.",
  "135": "Soos 'n beeswagter met 'n kierie beeste aanjaag weiveld toe, so jaag ouderdom en dood die lewe van lewende wesens aan.",
  "136": "Terwyl hy bose dade doen, besef die dwaas nie wat sal volg nie: 'n dom mens word deur sy eie dade verteer soos een deur vuur verbrand.",
  "137": "Wie die knuppel laat reën op onskadelike weerloses ondergaan self gou een van tien state:",
  "138": "wrede pyn, broodsgebrek, 'n gebroke liggaam, ernstige siekte, geestesversteuring,",
  "139": "moeilikheid met die koning, erge aantygings, afstaan van verwante, verlies van besittings,",
  "140": "of vuur verbrand sy huise – en as sy liggaam ontbind, word die dwaas in 'n hel herbore.",
  "141": "Nóg naak leef nóg vuil leef met gekoekte hare nóg vas nóg op die harde grond slaap nóg stof nóg modder nóg hurkend boete doen, reinig 'n sterfling wat twyfel nie oorkom nie.",
  "142": "'n Ewewigtige mens, selfs goed gekleed, wat rustig, beheers en met vertroue die edel lewe leef en geweld teenoor alle wesens aflê − so 'n mens is 'n brahmaan, swerwer, monnik.",
  "143": "In die wêreld is 'n mens wat deur gewete beteuel teregwysing voorkom soos 'n edel perd wat 'n sweepslag voorkom. Wees vurig wakker soos 'n edel perd deur die piets van 'n peits beheer.",
  "144": "Met vertroue en deug en inspanning, met konsentrasie en onderskeiding van die waarheid, volmaak in weet en leef asook aandagtig sal julle die groot lyding agterlaat.",
  "145": "Ingenieurs lei water, pylmakers buig stele, houtwerkers vorm hout, deugsames bemeester hulleself.",
  "chap11": "Ouderdom",
  "146": "Vanwaar gelag, vanwaar geluk gedagtig dat alles altyd brand? In duisternis gehul, soek julle dan nie lig nie?",
  "147": "Aanskou die opgesmukte vorm, die trotse versameling sere vol siekte en ambisie, nie-blywend nie-standhoudend.",
  "148": "Volledig vervalle is hierdie vorm, kortstondige broeiplek van siekte; 'n versameling vuil vergaan, want lewe eindig in dood.",
  "149": "Soos pampoendoppe in die herfs weggegooi is hierdie duif-grys beendere; kyk mooi daarna: het jy plesier?",
  "150": "In 'n vesting van been gebou en met vleis en bloed gepleister, word verval en dood en trots en voorgee weggesteek.",
  "151": "Versierde koetse van konings verval og die liggaam gaan tot niet maar die boodskap van goeie mense verval nie, want hulle deel dit aan goeie mense mee.",
  "152": "'n Mens wat nie hoor nie, word oud soos 'n os: sy vleis word meer, sy wysheid nie.",
  "153": "Deur die rondgang van talle geboortes malend het ek die bouer van die huis gesoek maar nie gevind nie; oor en oor gebore word, is lyding.",
  "154": "O, bouer van die huis, jy is gesien! Dié huis bou jy nie weer nie! Al die balke is gebreek en die nok aan stukke. Die gemoed is van samkhāra's vry, het die einde van begeertes bereik.",
  "155": "Wie die edel lewe nie geleef en in hul jeug die skat versamel het nie, kwyn weg soos afgeleefde reiers in 'n dam sonder vis.",
  "156": "Wie die edel lewe nie geleef en in hul jeug die skat versamel het nie, lê soos pyle uit boë weggeskiet treurend oor wat was.",
  "chap12": "Die Self",
  "157": "'n Mens wat homself waardevol ag, sal homself goed bewaak; deur minstens een van drie wake sal 'n wyse waaksaam wees.",
  "158": "Vestig eers jouself in wat reg is vóór jy raad aan ander gee; 'n wyse mens doen so nie skade nie.",
  "159": "Maak jouself só soos jy ander leer weer − laat 'n goed-getemde ander tem; waarlik, die self is moeilik tembaar.",
  "160": "Self is self se redder – wie anders kan redder wees? Deur jouself onder beheer te bring, bekom jy wat moeilik bekombaar is: 'n redder.",
  "161": "Die kwaad deur 'n mens self gedoen, uit 'n mens self gebore, deur 'n mens self voortgebring vergruis 'n dwaas soos 'n diamant 'n ander edelsteen.",
  "162": "As ondeug geil mens verstrengel soos 'n māluva-ranker 'n sāla-boom bring 'n mens oor jouself wat 'n vyand jou toewens.",
  "163": "Maklik is om te doen wat sleg is en jou skaad; uiters moeilik is om te doen wat nuttig is en goed.",
  "164": "Vanuit 'n verwronge perspektief minag 'n dwaas die boodskap van die edel arahante wat waarheid leef en soos die katthaka-riet bring hy vrugte voort tot sy eie vernietiging.",
  "165": "Jy self doen kwaad, deur jouself word jy vuil; jy self doen kwaad nie, deur jouself kom jy skoon; suiwer en onsuiwer is joune alone, niemand reinig 'n ander nie.",
  "166": "Skeep jou eie saak en taak nie af vir dié van 'n ander nie al is syne hoe groot; ken jou eie welsyn goed en jy sal die ware welsyn dien.",
  "chap13": "Die Wêreld",
  "167": "Hang 'n mindere waarheid nie aan en leef nie agloos nie; hang 'n verwronge siening nie aan en bevestig die wêreld nie.",
  "168": "Staan regop, wees nie agloos nie; leef die waarheid, die goeie lewe; wie die waarheid leef, is gelukkig in hierdie wêreld en die volgende.",
  "169": "Leef die waarheid, die goeie lewe, leef 'n lae lewe nie; wie die waarheid leef, is gelukkig in hierdie wêreld en die volgende.",
  "170": "Iemand wat die wêreld sien as 'n lugbel, 'n lugspieëling – hom sien Koning Dood nie.",
  "171": "Kom kyk na hierdie wêreld blink soos die koets van 'n koning; wie nie weet nie, swig, wie werklik weet, bly ongeheg.",
  "172": "Wie agloos was maar agloos nie meer is nie, verlig hierdie wêreld soos die maan uit 'n wolk bevry.",
  "173": "Wie se gedane slegte daad deur 'n goeie oordek word, verlig hierdie wêreld soos die maan uit 'n wolk bevry.",
  "174": "Verblind is die wêreld, min het helder insig; min styg hemelwaarts soos 'n voël uit 'n net bevry.",
  "175": "Swane sweef in die sonpad, met krag vlieg mense deur die luig, wyses styg bo die wêreld uit: het die Bose en sy bende oorwin.",
  "176": "Vir 'n mens wat die een waarheid loën, onwaarheid verkondig en sy rug op die ander wêreld keer, is geen kwaad ondoenbaar nie.",
  "177": "Suiniges betree die godewêreld nie en dwase beveel gee nie aan nie; 'n wyse vind genoeë in gee en is dus hierna gelukkig.",
  "178": "Beter as alleenmag oor die aarde of heengaan na 'n hemel or opperheerskappy oor alle wêrelde is die vrug van stroombetreding.",
  "chap14": "Die Verligte",
  "179": "Langs watter weg sal julle die spoorlose opsoor: die Verligte in die ruimte van eindeloosheid wat sy oorwinning nie sal verloor nie en wie se stryd hom nie volg nie?",
  "180": "Langs watter weg sal julle die spoorlose opsoor: die Verligte in die ruimte van eindeloosheid wat nêrens heen gesleep word in die net van verkleefdheid en begeerte nie?",
  "181": "Selfs die gode beny die wyses wat meditasie beoefen en geluk vind in die vrede van afstand doen: die aandagtiges, die Volverligtes.",
  "182": "Moeilik is dit om die menslike staat te bereik; moeilik die lewe van sterflinge; moeilik is dit om die goeie leer te hore te kom; moeilik die wording van Verligtes.",
  "183": "Geen boosheid doen nie, die goeie ontwikkel, die gees suiwer – dit is die boodskap van Boeddhas.",
  "184": "Volhardende geduld is die hoogste dissipline en nibbāna die hoogste staat, leer Boeddhas; die huislose doen geen geweld nie, the swerwer geen leed nie.",
  "185": "Nie krenkend praat nie, nie leed aandoen nie, in die perke van die kode leef, matig eet, eenkant lê en sit, jou aan dieper wete wy − dit is die boodskap van Boeddhas.",
  "186": "Geluk word in plesiere nie gevond nie al reën dit geld; die wyse weet plesier bevredig nie en bring pyn",
  "187": "en raak nie in vervoering nie al is dit hemels; wie geluk vind in die kwytraak van begeerte volg die Volverligte.",
  "188": "Angsbevange neem talle toevlug in berge en woude en parke met heilige bome.",
  "189": "Inderdaad is dié toevlug nie vas en seker nie, dié toevlug die beste nie; wie dáár toevlug geneem het, word nie van alle lyding vry nie.",
  "190": "Maar wie toevlug geneem het in die Verligte, die Leer en die Gemeenskap sien met volle insig die vier edel waarhede:",
  "191": "lyding, die verskyning van lyding, die verdwyning van lyding, die agtvoudige pad wat lei na die verdwyning van lyding.",
  "192": "Inderdaad is dié toevlug vas en seker, dié toevlug die beste; wie dáár toevlug geneem het, word van alle lyding vry.",
  "193": "'n Edel mens word moeilik gevind, word nie enige plek gebore nie; gelukkig is die familie waar so 'n wyse gebore word.",
  "194": "Geluk is die verskyning van Verligtes, geluk die meedeel van die ware Leer, geluk die eendrag van die Gemeenskap, geluk die Dissipline van Eendragtiges.",
  "195": "Een wat eerbiedwaardiges eer − Boeddhas en hulle dissipels wat die verstrooiings oorkom en jammerkla oorskry het,",
  "196": "vrede gevind het en niks meer vrees nie − so een se verdienste kan nie bereken word nie.",
  "chap15": "Geluk",
  "197": "Hoe gelukkig leef ons sonder haat onder mense wat haat; onder mense wat haat, woon ons sonder haat.",
  "198": "Hoe gelukkig leef ons sonder kwelling onder mense wat gekweld is; onder mense wat gekweld is, woon ons sonder kwelling.",
  "199": "Hoe gelukkig leef ons sonder onrus onder mense wat onrustig is; onder mense wat onrustig is, woon ons sonder onrus.",
  "200": "Hoe gelukkig leef ons wat niks het nie; ons sal van vreugde leef soos stralende gode.",
  "201": "Wie wen, skep haat, wie verloor, slaap sleg; wie wen en verloor laat vaar, slaap gelukkig: kalm mens.",
  "202": "Geen vuur is daar soos begeer, geen onheil soos haat, geen lyding soos die khandhas, geen vreugde groter as vrede.",
  "203": "Honger is die ergste siekte, samkhāras die ergste lyding; om dit werklik te weet, is die hoogste geluk: nibbāna.",
  "204": "Gesondheid is die grootste skat, tevredenheid die grootste rykdom, vertroue die grootste verwantskap, nibbāna die grootste geluk.",
  "205": "'n Mens wat afsondering gesmaak en vrede geproe het is sonder leed og kwaad en drink die vreugde van waarheid.",
  "206": "Om edeles te sien is goed, samesyn met sulkes bring altyd geluk; deur dwase nie te sien sal mens blywend gelukkig wees.",
  "207": "Wie in die geselskap van dwase beweeg, ly lank; met dwase saamleef, is so ellendig soos slepende vyandskap; met 'n bestendig-wyse mens saamleef, is gelukkig soos saamwees van verwante.",
  "208": "Vergesel dons 'n bestendig-wyse mens − 'n mens met insig en wete, getrou en toegewy, edel, deugsaam en intelligent - vergesel so 'n mens soos die maan 'n sterrebeeld op weg.",
  "chap16": "Behae",
  "209": "As jy jou inspan vir wat moeite nie werd is nie en vir wat moeite wel werd is jou nie inspan nie, as jy wat saak maak versaak og aan behae verknog is, sal jy 'n mens beny wat hom inspan vir wat saak maak.",
  "210": "Heg jou nie aan wat behaag og nie aan wat nie behaag; om nie te sien wat behaag og te sien wat nie behaag, is lyding.",
  "211": "Skep dus geen behae nie want verlies van behae is verdriet; vir wie nóg behae nóg onbehae tel bestaan daar geen boeie nie.",
  "212": "Uit behae spruit hartseer, uit behae spruit vrees; 'n mens van behae bevry het geen hartseer nie; vanwaar vrees?",
  "213": "Uit geneigdheid spruit hartseer, uit geneigdheid spruit vrees; 'n mens van geneigdheid bevry het geen hartseer nie; vanwaar vrees?",
  "214": "Uit lus spruit hartseer, uit lus spruit vrees; 'n mens van lus bevry het geen hartseer nie; vanwaar vrees?",
  "215": "Uit begeerte spruit hartseer, uit begeerte spruit vrees; 'n mens van begeerte bevry het geen hartseer nie; vanwaar vrees?",
  "216": "Uit smagting spruit hartseer, uit smagting spruit vrees; 'n mens van smagting bevry het geen hartseer nie; vanwaar vrees?",
  "217": "Mense het behae in iemand wat met deug en insig toegerus og aan die dhamma toegewy die waarheid praat og so sy eie taak volvoer.",
  "218": "'n Mens met ingebore heimwee na wat nie benoem kan word nie, sy gees deurdrenk daarvan og onverstrik deur sinplesiere − so een word genoem 'stroomoorsteker'.",
  "219": "As 'n mens lank ver weg was og veilig terugkeer, vier familie, vriende en kennisse sy tuiskoms;",
  "220": "so verwelkom sy deugsame dade 'n deugsame mens wanneer hy vertrek.",
  "chap17": "Woede",
  "221": "Lê woede af, sluit ydelheid uit en laat elke binding agter; geen leed oorval 'n mens wat ongeheg aan naam-en-vorm aan niks kleef nie.",
  "222": "Wie opstuiwende woede beheer soos 'n slingerende koets noem ek 'koetsier'; ander hou net die teuels.",
  "223": "Oorwin woede met sagmoedigheid boosheid met goedheid gierigheid met vrygewigheid leuenagtigheid met waarheid.",
  "224": "Praat die waarheid, word nie kwaad nie en gee as jy gevra word al het jy min; deur hierdie drie optredes kom 'n mens digby die gode.",
  "225": "Wyses wat sonder geweld die liggaam immer beheer, bereik die staat van nie-dood; daar treur hulle nie.",
  "226": "Wie altyd waaksaam dag en nag oefen en op nibbāna gerig is se sere verdwyn.",
  "227": "So was dit altyd, Atula, nie net vandag nie: hulle vind fout as 'n mens niks praat, hulle vind fout as 'n mens veel praat, hulle vind fout as 'n mens min praat; met niemand in hierdie wêreld word fout nie gevind nie.",
  "228": "Daar was nooit 'n mens en daar sal nooit een wees en daar is nou nie een met wie totaal fout gevind word of wat totaal geprys word nie.",
  "229": "Maar een deur wyses geprys ná langdurige waarneming se gedrag is sonder barste en hy is wys, met insig en deug geïntegreer.",
  "230": "Wie is werd om fout te vind met so 'n sieraad van Jambu-goud? Selfs die gode loof so 'n mens; selfs deur Brahmā word hy geloof.",
  "231": "Waak teen woede in liggaam, wees beheers in liggaam; verwerp wangedrag in liggaam, leef goed in liggaam.",
  "232": "Waak teen woede in woorde, wees beheers in woorde; verwerp wangedrag in woorde, leef goed in woorde.",
  "233": "Waak teen woede in denke, wees beheers in denke; verwerp wangedrag in denke, leef goed in denke.",
  "234": "Wyses is beheers in liggaam, beheers in woorde, beheers in denke; wyses is waarlik volkome beheers.",
  "chap18": "Smette",
  "235": "'n Verlepte blaar, so is jy nou, die boodskappers van Yama wag al, jy staan op die drumpel van vertrek − en jy het nie voorberei nie.",
  "236": "Maak 'n eiland vir jouself: span jou terstond in en word wys, van smette skoon en van vlekke gereinig − und jy sal die goddelike staat van edeles binnegaan.",
  "237": "Naby jou einde is jy nou, bevind jou in die buurt van Yama, het intussen selfs geen rusplek nie − en jy het nie voorberei nie.",
  "238": "Maak 'n eiland vir jouself: span jou terstond in en word wys, van smette skoon en van vlekke gereinig − und jy sal gebore en oud word nie weer binnegaan nie.",
  "239": "Geleidelik, bietjie vir bietjie, oomblik na oomblik sal 'n wyse mens sy eie smette uitsuiwer soos 'n smid onsuiwerheid uit silwer.",
  "240": "Soos roes wat uit yster ontstaan, wegvreet waaruit dit ontstaan, so lei onmatig lewendes se eie dade hulle tot 'n staat van leed.",
  "241": "Nie-inoefening besoedel die woorde, nie-opruiming besoedel wonings, nie-versorging besoedel voorkoms, nalatigheid besoedel 'n wagter.",
  "242": "Die smet van 'n vrou is wangedrag, die smet van 'n gewer suinigheid; slegte sentimente is smette in hierdie lewe en hierna.",
  "243": "'n Erger smet nog as dit is onkunde, die aller-ergste smet; verwyder hierdie smet en word smetteloos, o monnike.",
  "244": "Lekker leef 'n kraai-mens: skaamteloos gewetensloos, brutaal, spoggerig, voortvarend, korrup;",
  "245": "swaar leef 'n gewetensvolle mens: immer suiwerheidsoekend, onverknog, beskeie, skoon lewend, skerpsiende.",
  "246": "'n Man wat in die wêreld asem vernietig, onwaarheid verkondig, neem wat nie gegee is nie, 'n ander man se vrou besoek en",
  "247": "hom aan sterk drank verslaaf, ontwortel homself in hierdie einste wêreld.",
  "248": "Weet dít, goeie vriend: verkeerde dade ruk handuit; moenie dat hebsug en wangedrag jou in langdurige ellende dompel nie.",
  "249": "Mense gee volgens oortuiging en neiging; wie ontsteld is oor ander se kos en drank sal dag of nag nooit konsentrasie bereik nie.",
  "250": "Maar iemand by wie hierdie ontsteltenis verwyder, radikaal uitgeroei en vernietig is sal dag of nag konsentrasie bereik.",
  "251": "Geen vuur is soos hartstog, geen houvas soos haat, geen strik soos verwarring, geen rivier soos dors.",
  "252": "Maklik is dit om die fout van andere raak te sien, moeilik om jou eie raak te sien; 'n mens wan andere se foute soos kaf, verdoesel jou eie soos 'n slu dobbelaar sy skelmstreek.",
  "253": "'n Mens wat gedurig foutvinderig uitkyk vir die foute van ander se eie onsuiwerhede neem toe; ver van die beëindiging van onsuiwerhede is hy.",
  "254": "In die oopte is geen weg en geen swerwer is daarbuite; die mensdom is lief vir denkkonstrukte maar Tathāgatas is vry van denkkonstrukte.",
  "255": "In die oopte is geen weg en geen swerwer is daarbuite; saamgestelde dinge is nie ewig nie en Boeddhas is vry van onsekerheid.",
  "chap19": "In Die Waarheid Staande",
  "256": "Wie willekeurig oor 'n saak beslis staan nie in die waarheid nie; wie albei kante opweeg is 'n wyse mens.",
  "257": "Wie geweldloos en onpartydig ander volgens die waarheid rig, want self deur die waarheid gelei en verstandig, word 'waaragtig' genoem.",
  "258": "Wys is 'n mens nie omdat hy baie praat nie; 'wys' word 'n mens genoem wat vredevol, vriendelik en vreesloos is.",
  "259": "Waarheidsdraer is 'n mens nie omdat hy baie praat nie; waarheidsdraer is 'n mens wat al het hy min daarvan verneem waarheid aan sy eie lyf ervaar en waarheid nie laat vaar.",
  "260": "Senior is 'n mens nie omdat sy hare grys is nie; 'n mens kan ryp in jare wees en tog 'vergeefs vergrys' genoem word.",
  "261": "'Senior' word 'n mens tereg genoem in wie waarheid en waaragtigheid is, wat geweldloos, beheersd en matig is en wys, van onsuiwerheid ontslae.",
  "262": "Eerbiedwaardig is 'n mens nie as hy welsprekend en indrukwekkend van voorkoms maar afgunstig, selfsugtig en bedrieglik is nie.",
  "263": "'Eerbiedwaardig' word 'n mens tereg genoem in wie hierdie drie smette wortel en tak uitgeroei is: 'n wyse mens van haat ontslae.",
  "264": "Swerwer is 'n mens nie as hy met kaalgeskeerde kruin sy taak versaak en 'n leuen leef nie: hoe sal 'n mens vol gierige begeerte swerwer wees?",
  "265": "'Swerwer' word 'n mens tereg genoem wat alle boosheid fyn en grof laat bedaar, verstil.",
  "266": "Monnik is 'n mens nie net as hy bij ander bedel nie; en monnik is 'n mens nie as hy 'n slegte lewenskode volg nie.",
  "267": "'Monnik' word hy tereg genoem wat anderkant goed en kwaad 'n hoër lewe leef en onderskeidend deur die wêreld reis.",
  "268": "Denker is 'n mens nie net omdat hy swyg nie – dalk verward verdwaas; die wyse mens wat weeg, die goeie behou",
  "269": "en die kwade vermy, is dáárom waarlik denker; wie albei in die wêreld deurgrond word 'denker' genoem.",
  "270": "Edel is 'n mens nie as hy lewende wesens geweld aandoen nie; wie lewende wesens geen geweld aandoen nie, word 'edel' genoem.",
  "271": "Nie met die uitleef van morele reëls of die nakom van rituele voorskrifte of groot geleerdheid of diep meditasie of apart leef",
  "272": "(denkend: 'ek geniet die geluk van wêreldversaking voor gewone mense onbeskore') moet jy, o monnik, tevrede wees solank jy nie smetloos is nie.",
  "chap20": "Die Pad",
  "273": "Van paaie is die agtvoudige die beste; van waarhede, die vier beginsels; van geestesgesteldhede is afgeskeidenheid die beste; van tweebenige wesens, die heldersiende.",
  "274": "Dit is die pad wat lei na suiwerheid van insig, die enigste; volg hierdie pad wat lei na die verblinding van Māra.",
  "275": "As julle hierdie pad betree sal julle 'n einde aan lyding maak; ek het die dorings leer uithaal en die pad bekend gemaak.",
  "276": "Volvoer self jul taak met ywer want Tathāgatas bied net lering; wie dié pad mediterend betree kom los uit die binding van Māra.",
  "277": "'Nie-blywend is alle saamgestelde dinge'; wanneer 'n mens dit met wysheid insien draai jy weg van lyding: dit is die weg na suiwerheid.",
  "278": "'Nie-bevredigend is alle saamgestelde dinge'; wanneer mens dit met wysheid insien draai jy weg van lyding: dit is die weg na suiwerheid.",
  "279": "'Nie-selfgenoegsaam is alle verskynsels'; wanneer mens dit met wysheid insien draai jy weg van lyding: dit is die weg na suiwerheid.",
  "280": "'n Sterk maar trae jongmens wat nie betyds opstaan nie maar letargies bly lê met 'n gees vol onderdrukte gedagtes is lui en vind die weg na wysheid nie.",
  "281": "Bewaak spraak, beheers gedagtes en handel met lyf nie verkeerd nie: louter die drie paaie van daad en bereik so die weg deur sieners onthul.",
  "282": "Waarlik, deur dissipline ontstaan wysheid en deur versuim vergaan wysheid; bewus van die dubbelpad of vooruitgang en agteruitgang behoort mens die koers in te slaan waarlangs wysheid toeneem.",
  "283": "Verwyder die oerwoud en nie net 'n boom nie want uit oerwoud word vrees gebore; verwyder boombos en kreupelbos: wees begeerteloos, o monnike.",
  "284": "Solank kreupelbos-begeerte hoe gering ook al van 'n man na vroue nie verwyder is nie, bly sy gees gebonde soos 'n suipkalf aan sy ma.",
  "285": "Maak self-verknogtheid tot niet soos 'n mens met jou hand 'n wit lotus in herfstyd pluk; koester slegs die pad na kalmte: nibbāna deur die Sugata onderrig.",
  "286": "'Hier sal ek in die reënseisoen vertoef en hier in die winter en die somer' dink die dwaas sonder nadink oor verhindering.",
  "287": "Soos 'n stormvloed 'n slapende dorp oorval, sleur die dood die man mee wat begerig van gees op sy kinders en vee versot is.",
  "288": "Vir 'n mens in die greep van die Beëindiger bied naasbestaandes geen beskerming nie: nóg seuns nóg vader nóg verwante kan skuiling bied.",
  "289": "In die besef van hierdie onomstootlikheid sal die wyse, deur deug beheer, betyds die pad skoonmaak wat na nibbāna lei.",
  "chap21": "Allerlei",
  "290": "As 'n mens deur prysgawe van 'n geringe geluk 'n groot geluk sou aanskou, sal 'n wyse mens die geringe geluk laat vaar met die oog op die groot geluk.",
  "291": "Wie geluk vir homself wens deur ander wesens te laat ly, bly in die strik van haat gevang, word nie van haat bevry nie.",
  "292": "Wat gedoen behoort te word, word verwaarloos en wat nie gedoen behoort te word nie word gedoen – en die swere van ydel, agtelosige mense bly deurentyd groei.",
  "293": "Maar die swere verdwyn van diegene wat aandagtig en noulettend is, wie se aandag altyd vas op die liggaam gevestig is, wat nie doen wat nie gedoen moet word nie maar volhardend doen wat gedoen moet word.",
  "294": "Die edel mens het moeder en vader en twee krygerkonings doodgemaak en 'n koninkryk met sy bevolking vernietig en beweeg onverskrokke voort.",
  "295": "Die edel mens het moeder en vader en twee geleerde konings doodgemaak e die vyftallige tier vernietig en beweeg onverskrokke voort.",
  "296": "Die volgelinge van Gotama ontwaak immer helder wakker: hul aandag dag en nag bly by die Ontwaakte.",
  "297": "Die volgelinge van Gotama ontwaak immer helder wakker: hul aandag dag en nag bly by die waarheid.",
  "298": "Die volgelinge van Gotama ontwaak immer helder wakker: hul aandag dag en nag bly by die gemeenskap.",
  "299": "Die volgelinge van Gotama ontwaak immer helder wakker: hul aandag dag en nag bly by die liggaam.",
  "300": "Die volgelinge van Gotama ontwaak immer helder wakker: hul gees vind dag en nag vreugde in geweldloosheid.",
  "301": "Die volgelinge van Gotama ontwaak immer helder wakker: hul gees vind dag en nag vreugde in meditasie.",
  "302": "Swaar en swaar om te geniet is die huislose staat en swaar is die huislike staat; swaar is die lewenstaat saam met ongelykes en swaarkry oorval dwalendes. Wees dus 'n dwalende nie en word deur swaarkry nie oorval nie.",
  "303": "'n Mens vol vertroue en toegerus met deug verwerf aansien en welvaart en word geëer oral waar hy kom.",
  "304": "Grootse mense word van ver gesien soos sneeubedekte pieke; swakkes bly hier ongesien, soos pyle in die nag geskiet.",
  "305": "Een wat alleen sit, alleen lê, alleen loop, homself onvermoeid alleen tem, sal aan die rand van die woud gelukkig weer.",
  "306": "'n Mens wat sê wat nie is nie en een wat onreg pleeg e dan sê 'ek het dit nie gedoen nie' gaan hul ondergang tegemoet; nadoods hiernamaals is hierdie mensgeborenes eenders: albei ewe laag van daad og lot.",
  "chap22": "Ondergang",
  "307": "Talle met 'n geel kleed behang, is swak van inbors en onbeheersd; hierdie slegtes word in ellende herbore as gevolg van hul bose dade.",
  "308": "Vir 'n monnik is dit beter om 'n vurig gloeiende ysterbal in te sluk as om ondeugsaam onbeheers 'n land se voedsel te verorber.",
  "309": "'n Roekelose man wat 'n ander se vrou opsoek maak met vier dinge kennis: vergelding, sleg slaap, skande en ondergang;",
  "310": "vergelding, slegte bestemming, min plesier van 'n bang man by 'n bang vrou en swaar straf deur die koning. Dus: laat 'n man 'n ander se vrou nie opsoek nie.",
  "311": "Soos kusa-gras verkeerd gegryp die hand sny, lei swerwerskap verkeerd hanteer tot ondergang.",
  "312": "'n Trae daad, geskonde kode en skyn-edel lewe lewer nie 'n goeie oes op nie.",
  "313": "Doen wat gedoen moet word met alle krag; 'n halfhartige swerwer skop homself vol stof.",
  "314": "Die nie-doen van sleg-doen is beter, want sleg-doen folter later, maar die wel-doen van reg-doen is beter, want reg-doen berou 'n mens nooit.",
  "315": "Bewaak julleself soos 'n vestingstad op 'n grens binnekant en buitekant bewaak word; laat geen oomblik ontglip nie, want wie die geleentheid laat glip, betreur dit, aan ondergang uitgelewer.",
  "316": "Menge wat slegte sienings huldig, is beskaamd waar skaamte nie pas nie en skaamteloos waar skaamte pas, en beweeg op 'n slegte weg.",
  "317": "Mense wat slegte sienings huldig, is bevrees waar vrees nie pas nie en onbevrees waar vrees pas, en beweeg op 'n slegte weg.",
  "318": "Mense wat slegte sienings huldig, vind fout waar geen fout is nie en sien geen fout nie waar wel fout is, en beweeg op 'n slegte weg.",
  "319": "Mense wat regte sienings huldig weet dat fout fout is en dat reg reg is, en beweeg op 'n regte weg.",
  "chap23": "Die Olifant",
  "320": "Soos 'n olifant in 'n veldslag 'n pyl uit 'n boog verduur sal ek krenktaal verduur, want boos is die mensdom.",
  "321": "Hulle lei 'n getemde olifant tussen 'n skare mense in en 'n koning bestyg 'n getemde een; 'n getemde mens wat krenktaal verduur is onder mensekinders die beste.",
  "322": "Voortreflik is getemde muile, volbloed Sindhu-perde en groottand-olifante, maar veel voortrefliker is 'n self-getemde mens.",
  "323": "Nie op hierdie voertuie sou 'n mens die onbegane land bereik nie, want dáár kom net 'n getemde met 'n goed getemde self.",
  "324": "Die olifant genaamd Dhanapālaka is met paartyd moeilik beheerbaar; vasgebind vreet hy niks, onthou net die olifantwoud.",
  "325": "Traag en verknog soos 'n vark wat heeldag vreet en slaap word 'n luiaard oor en oor gebore.",
  "326": "Tot dusver het hierdie gees rondgedwaal agter lus aan net waar en wanneer e soos dit wou, maar van vandag af sal ek dit metodies beheer soos 'n olifanttemmer 'n bronstige bul.",
  "327": "Vind genoeë in agsaamheid, bewaak jou eie gees, lig jouself op uit die moeraspad soos 'n olifant in modder weggesink.",
  "328": "As jy 'n verstandige metgesel vind, 'n reisgenoot wat alle gevare oorwin het en deugsaam e bestendig leef, reis dan gelukkig en aandagtig saam met so 'n mens.",
  "329": "As jy 'n verstandige metgesel, 'n reisgenoot wat deugsaam e bestendig leef, nie vind nie, moet jy soos 'n koning wat 'n oorwonne ryk verlaat het, soos 'n olifant in die Mātanga-woud, alleen loop.",
  "330": "Alleen loop is verkieslik want met 'n dwaas is daar nie vriendskap nie; loop alleen sonder boos doen, sorgloos soos 'n olifant in die Mātanga-woud.",
  "331": "Geluk is vriendskap in 'n tyd van nood, vrede in elke sin, verdienste by die lewensend, agterlaat van alle leed.",
  "332": "Geluk is eerbied vir 'n moeder, eerbied vir 'n vader, eerbied vir 'n swerwer, eerbied vir 'n edel mens.",
  "333": "Geluk is deug tot in die ouderdom, vertroue vas gevestig, bereiking van insig, nie-doen van boosheid.",
  "chap24": "Begeerte",
  "334": "Die begeerte van 'n mensgeborene wat agloos leef, groei soos 'n māluvā-ranker e so 'n mens swaai van bestaan tot bestaan soos 'n woud-aap wat vrugte begeer.",
  "335": "Wie in hierdie wêreld oorwin word deur begeerte waardeloos e verstrengelend se smarte skiet op so 'n reën-deurweekte bīrana-gras.",
  "336": "Wie in hierdie wêreld oorwin oor begeerte waardeloos e moeilik om van los te kom se smarte gly af soos druppels water van 'n lotusblaar.",
  "337": "Heil maak ek julle bekend, julle almal hier vergader: grawe die wortel van begeerte uit soos 'n mens op soek na die soetruik-wortel van bīrana-gras. Laat Māra julle nie oor e oor oorweldig soos 'n rivier met rietgras doen nie.",
  "338": "'n Afgekapte boom loop immer uit solank sy wortel sterk e onbeskadig bly; so bot lyding oor e oor solank die neiging van begeerte onvernietig bly.",
  "339": "'n Mens wat 'n verkeerde siening huldig, by wie die ses-en-dertig strome sterk na aangename dinge vloei, word deur sy lus-behepte denke meegesleur.",
  "340": "Oral vloei die strome e die ranker spruit uit e bly staan; sien die opgeskote ranker e kap sy wortel met wysheid uit.",
  "341": "Strome klewende plesiere wel in mense op; plesiersoekers aan bevrediging geheg hou aan gebore-en-oud word.",
  "342": "Van begeerte deurtrek skarrel mense soos verskrikte hase rond; gebind met kettings e boeie ly hul oor e oor e lank.",
  "343": "Van begeerte deurtrek skarrel mense soos verskrikte hase rond; 'n monnik wat begeerteloosheid soek sal begeerte uit homself verwyder.",
  "344": "Aanskou daardie mens: eers was hy los uit die bos van begeerte e gerig op die woud van verwydering; maar, eens bevry van begeerte, haas hy hom terug na begeerte; bevry, yl hy terug na gevangenskap.",
  "345": "Die wyses sê 'n band van yster, hout of tou is nie sterk nie, maar gehegtheid aan edelstene e juwele e begeerte na seuns e vroue",
  "346": "is 'n sterk band, na benede slepend, slap maar moeilik om uit los te kom.",
  "347": "Lusbeheptes val in die maalstroom, is soos 'n spinnekop in haar self-gemaakte web; die wyses sny hulleself los om begeerteloos alle leed te verlaat e voort te beweeg.",
  "348": "Laat vaar wat voorlê, laat vaar wat verby is e laat vaar wat tussen-in kom; bereik die ander oewer van bestaan e met 'n gees in alle opsigte vry kom jy by gebore word e oud word nie weer nie.",
  "349": "In 'n mens met wroegende denke gulsig begerend op die uitkyk na bevrediging groei begeerte al geiler – so 'n mens maak sy gebondenheid vaster.",
  "350": "Maar 'n mens wat behae vind in die bedaring van denke e immer aandagtig mediteer oor wat geen bevrediging bied sal begeerte tot 'n einde bring, die binding van Māra verbreek.",
  "351": "Wie die doel bereik het is vreesloos e begeerteloos: vlekloos, e het die pyle van bestaan verwyder; dit is sy laaste liggaam.",
  "352": "'n Mens sonder begeerte e vry van klewing, 'n kenner van die taal e komposisie van die skrifte, word tereg 'belewer van die laaste liggaam', 'groot wyse', 'groot mens' genoem.",
  "353": "Oorwinnaar oor alles e kenner van alles is ek aan niks gebind nie; bevry deur verval van begeerte het ek alles verlaat; self het ek tot insig gekom – wie sou ek meester noem?",
  "354": "Die gawe van waarheid oortref alle gawes, die smaak van waarheid oortref alle smake, die genoeë van waarheid oortref alle genoeëns, die verval van begeerte oorwin alle leed.",
  "355": "Rykdom vernietig die dwaas, maar nie hulle wat die ander oewer soek nie; met sy begeerte na rykdom vernietig die dwaas homself soos ander.",
  "356": "Onkruid besmet landerye e begeerte besmet die mensdom; 'n gawe aan mense vry van begeerte lewer oorvloedige vrug.",
  "357": "Onkruid besmet landerye e haat besmet die mensdom; 'n gawe aan mense vry van haat lewer oorvloedige vrug.",
  "358": "Onkruid besmet landerye e verblinding besmet die mensdom; 'n gawe aan mense vry van verblinding lewer oorvloedige vrug.",
  "359": "Onkruid besmet landerye e lus besmet die mensdom; 'n gawe aan mense vry van lus lewer oorvloedige vrug.",
  "chap25": "Die Monnik",
  "360": "Beheer oor die oog is goed, goed is beheer oor die oor; beheer oor die neus is goed, goed is beheer oor die tong;",
  "361": "beheer oor die liggaam is goed, goed is beheer oor die taal; beheer oor die gees is goed, goed is beheer in alle opsigte; die monnik in alle opsigte beheers is van alle leed vry.",
  "362": "Wie beheers is van hand, voet, spraak en denke, in innerlikheid behae vind en aandagtig as alleenling gelukkig is – hóm noem hulle 'monnik'.",
  "363": "Soet is die taal van 'n monnik wat beheers in spraak nederig en met insig praat en die boodskap en sy strekking so verhelder.",
  "364": "Die monnik wat in die waarheid woon, in die waarheid vreugde vind, oor die waarheid nadink en die waarheid in gedagte hou, val nie van die hoë waarheid weg nie.",
  "365": "Laat 'n bedelmonnik nie minag wat hy kry nie en ander hul wins nie beny nie; wie ander hul wins beny bereik nie konsentrasie nie.",
  "366": "Selfs die gode loof 'n monnik wat slegs weinig kry en tog nie minag wat hy kry nie, maar suiwer werksaam leef.",
  "367": "Wie ongeheg aan naam-en-vorm nie treur oor what nie is nie, word waarlik 'monnik' genoem.",
  "368": "Die monnik wie se tuiste liefde is en vreugde vind in die Boeddha-leer sal die staat van vrede bereik, die stilword van emosie-en-wil: geluk.",
  "369": "Monnik, skep hierdie skip leeg, want leeg sal dit lig beweeg; as jy lus en afsku afsny sal jy nibbāna bereik.",
  "370": "Sny vyf af gee vyf prys ontwikkel vyf van vyf boeie los word 'n monnik 'stroomoorsteker' genoem.",
  "371": "Monnik, mediteer en wees nie agloos nie, laat jou gees in sinplesier nie dwaal nie, sluk nie nalatig 'n gloeiende metaalbal in en jammer dan brandend 'dit is pynlik' nie.",
  "372": "Daar is geen diep meditasie by wie insig kortkom nie en geen insig by wie diep meditasie kortkom nie; een by wie diep meditasie sowel as insig voorkom is waarlik naby nibbāna.",
  "373": "'n Monnik wat die leë tuiste binnegaan, sy gees tot kalm bedaring bring en die waarheid helder insien, ervaar geluk meer as menslik.",
  "374": "Deeglik denkend oor khandhas se verskyning en verdwyning beleef hy vreugde en genoeë: nie-dood vir wie verstaan.",
  "375": "Hier is die vertrekpunt vir 'n wyse monnik: bewaking van die vermoëns, tevredenheid, dissipline in die monnikskode en omgang met edel vriende wat suiwer en standvastig leef.",
  "376": "Laat hom wellewend in die omgang wees en vaardig in gedrag – dan sal hy vol vreugde lyding beëindig.",
  "377": "O monnike, skud lus en haat af soos jasmyn verlepte blomme.",
  "378": "'n Monnik rustig ferm, kalm van liggaam, woord en gees en van wêreldslus ontslae word 'bedaard' genoem.",
  "379": "Deur jouself bemoedig, deur jouself beteuel, self-beheersd en aandagtig sal jy, o monnik, gelukkig leef.",
  "380": "Jyself is jou toevlug en jyself is jou gids; beheer dus jouself soos 'n handelaar 'n edel perd.",
  "381": "'n Monnik vol vreugde en vertroue in die Boeddha-leer sal die staat van vrede en geluk bereik: die bedaring van gekondisioneerde dinge.",
  "382": "'n Monnik wat hom in sy jeug aan die Boeddha-leer verbind, bestraal die wêreld waarlik soos die maan van wolke vry.",
  "chap26": "Edel Mens",
  "383": "Edel mens, span jou in en klief die stroom; laat sintuiglike begeertes vaar en weet dat samestellings ontbind; dan ken jy nie-gevormdheid, is jy edel mens.",
  "384": "Wanneer 'n edel mens in albei dimensies die ander oewer bereik het, is hy 'n mens wat weet en val al sy boeie weg.",
  "385": "'n Mens wat verdwyn het aan oorkant of duskant of albei, onbevrees en onverbonde, noem ek 'edel mens'.",
  "386": "'n Suiwer mens wat bestendig mediteer, gedoen het wat gedoen moet word en smetteloos die hoogste peil bereik het, noem ek 'edel mens'.",
  "387": "Bedags skyn die son snags glim die maan bewapen blink die kryger mediterend gloei die edel mens maar immer dag en nag skitter die Verligte.",
  "388": "Wie boosheid verban, word daarom edel mens, wie kalm leef daarom askeet en wie eie kwaad versaak daarom versaker genoem.",
  "389": "Slaan 'n edel mens nie – maar laat 'n geslaande edel mens geen woede uiter nie; 'n skande is dit om 'n edel mens te slaan – maar 'n groter skande is dit as die edel mens voor woede swig.",
  "390": "Vir 'n edel mens is daar niks beter nie as om sy gees van plesiersug te weerhou; namate die drang om te beseer verdwyn, bedaar lyding.",
  "391": "Een wat nie verkeerd doen in liggaam woord en gedagte nie maar in al drie opsigte beheersd is noem ek 'edel mens'.",
  "392": "Soos 'n brahmaan aan 'n offervuur moet jy opreg eerbied betoon aan een by wie jy die dhamma leer ken – die dhamma deur die Volmaak Verligte onderrig.",
  "393": "Edel mens is jy nie omrede van jou gekoekte haarstyl, afkoms of geboorte nie; edel mens suiwer is jy as waarheid en waaragtigheid in jou woon.",
  "394": "O dwaas, waardeloos is 'n gekoekte haarstyl en kleed van antiloopvel; in jou groei 'n geil bosgasie al is jy buite hoe fyn uitgevat.",
  "395": "'n Mensekind geklee in lappe van 'n rommelhoop uitgeteer met are sigbaar oor sy hele lyf alone in 'n woud mediterend noem ek 'edel mens'.",
  "396": "Ek noem niemand 'edel mens' vanweë sy afkoms of vername moeder nie (so een is welaf en sê 'meneer'). Nee, iemand wat niks het en niks wil hê nie noem ek 'edel mens'.",
  "397": "Wie alle belemmeringe afgesny het en onbevrees is, alle verknogthede oorkom het en vry is, noem ek 'edel mens'.",
  "398": "Wie tou en toom en teuel en stang gebreek, die dwarsbalke gelig het en verlig is noem ek 'edel mens'.",
  "399": "Wie belediging, aanranding en inkerkering sonder bitterheid verduur met duldkrag so sterk soos 'n weermag noem ek 'edel mens'.",
  "400": "Wie sonder woede plig volbring, sonder lus deugsaam leef en beheersd die laaste liggaam dra noem ek 'edel mens'.",
  "401": "Aan wie sinplesier nie kleef nie so min as water aan 'n lotusblaar of mosterdsaad aan 'n naald se punt noem ek 'edel mens'.",
  "402": "Wie in hierdie lewe die las neerlê en volkome vry die einde van sy leed ervaar noem ek 'edel mens'.",
  "403": "Wie diepe kennis het en wys is, regte pad van slegte pad can onderskei en die hoogste goed bereik het noem ek 'edel mens'.",
  "404": "Wie onverbonde bly aan huisbewoners en -verlaters, woningloos swerf en weinig wens noem ek 'edel mens'.",
  "405": "Wie die knuppel neerlê voor wesens swak of sterk en nie doodmaak of laat doodmaak nie noem ek 'edel mens'.",
  "406": "Wie by vyandiges vriendelik is, bij geweldenaars rustig en by gieriges vrygewig noem ek 'edel mens'.",
  "407": "Van wie begeerte en haat en trots en huigel afgeval het soos mosterdsaad van 'n naald se punt noem ek 'edel mens'.",
  "408": "Wie se woorde aangenaam, insiggewend en waar is en niemand kwets nie noem ek 'edel mens'.",
  "409": "Wie in hierdie wêreld nie neem wat nie gegee wordt nie hetsy lank of kort, klein of groot, mooi of lelik noem ek 'edel mens'.",
  "410": "Wie wensloos en vry na niks hunker nie nóg in hierdie wêreld nóg hierna noem ek 'edel mens'.",
  "411": "Wie sonder verknogthede deur insig by twyfel verby nie-dood bereik noem ek 'edel mens'.",
  "412": "Wie in hierdie wêreld die bande van goed sowel as kwaad oorkom e leedloos smetloos suiwer is noem ek 'edel mens'.",
  "413": "Wie soos die moon smetloos suiwer helder kalm is, ontdaan van smagting na bestaan, noem ek 'edel mens'.",
  "414": "Wie hierdie moerassige maling van bestaan, bedrieglik e moeilik begaanbaar, deurkruis e oorgesteek e die ander kant bereik het e sonder drif e weifel aan niks verknog nie mediterend uitgewoed is noem ek 'edel mens'.",
  "415": "Wie hier van genot ontslae woningloos swerf, bestaansbegeerte geblus, noem ek 'edel mens'.",
  "416": "Wie hier van gesmag ontslae woningloos swerf, bestaansgesmag geblus, noem ek 'edel mens'.",
  "417": "Wie van menslike binding los e van goddelike binding ontslae van alle bindinge volkome vry is, noem ek 'edel mens'.",
  "418": "Wie van behae e onbehae ontslae afgekoel e van die grondslae vry helder-oorwinnaar oor die hele wêreld is, noem ek 'edel mens'.",
  "419": "Wie onverbonde, gelukkig e verlig in elke opsig ervaringskennis dra van die verdwyning e verskyning van wesens noem ek 'edel mens'.",
  "420": "Wie se bestemmingsgang gode, halfgode e mense nie ken nie, een van onsuiwerhede skoon, 'n arahant, noem ek 'edel mens'.",
  "421": "Wie onverknog vashou aan niks in verlede, hede of toekoms nie noem ek 'edel mens'.",
  "422": "Wie edel stier e held is, groot wyse e oorwinnaar begeerteloos ontwaak in louter wete noem ek 'edel mens'.",
  "423": "Wie sy voriges lewens ken, hemele e helle sien e die einde van geboortes bereik het, wie as wyse hoër wete verwerf e volmaaktheid volkome volmaak het, noem ek 'edel mens'."
};
